def UMoELayer(x, X):
    # x: [1, d], X: [n, d]
    ### Attention MoE
    indices, probs = TopKRouter(x) # Assign token x to Experts
    residual_x = x.copy()
    K = X @ W_k
    q_shared = x @ W_q
    for i, p in zip(indices, probs):
        q = q_shared + x @ W_a[i] @ W_b[i]
        # K and V (the hidden states X) are shared across experts.
        y = Attention(Q=q, K=K, V=X)
        residual_x += p * Experts[i](y)
    x = residual_x
    ### FFN MoE
    indices, probs = TopKRouter(x) # Assign token x to Experts
    residual_x = x.copy()
    for i, p in zip(indices, probs):
        residual_x += p * Experts[i](x)
    return residual_x
\end{lstlisting}
\caption{Implementation details of a \tool layer. The input consists of a sequence X containing n token hidden states and x representing the final hidden state. For simplicity, this implementation focuses on computing the output for the last token.
}
